<?php
namespace App\Domain\Loans\Actions;
use App\Domain\Credit\Services\CreditPolicyEvaluator;use App\Models\LoanApplication;use App\Models\LoanApplicationGuarantor;use App\Models\Member;use Illuminate\Validation\ValidationException;
class AddLoanGuarantor{public function __construct(private CreditPolicyEvaluator $policy){}public function execute(LoanApplication $application,Member $guarantor,array $data):LoanApplicationGuarantor{if($application->member_id===$guarantor->id)throw ValidationException::withMessages(['guarantor_member_id'=>['A member cannot guarantee their own loan.']]);$application->loadMissing('product');$capacity=$this->policy->guarantorCapacity($application->product,$data['facts']);if(!$capacity['eligible']||$data['guaranteed_amount_minor']>$capacity['available_exposure_minor'])throw ValidationException::withMessages(['guaranteed_amount_minor'=>['The requested guarantee exceeds available capacity.']]);return LoanApplicationGuarantor::query()->create(['loan_application_id'=>$application->id,'guarantor_member_id'=>$guarantor->id,'guaranteed_amount_minor'=>$data['guaranteed_amount_minor'],'capacity_snapshot'=>$capacity,'status'=>'pending']);}public function consent(LoanApplicationGuarantor $guarantor,string $decision):LoanApplicationGuarantor{$guarantor->update(['status'=>$decision,'consented_at'=>now()]);return $guarantor->refresh();}}
